def login_verify_otp_view(request):
    """Verify login OTP."""
    user_id = request.session.get("login_otp_user_id")
    otp_id = request.session.get("login_otp_id")

    if not user_id or not otp_id:
        messages.error(request, "Session expired. Please login again.")
        return redirect("login")

    try:
        user = CustomUser.objects.get(id=user_id)
        otp_record = LoginOTP.objects.get(id=otp_id, user=user)
    except (CustomUser.DoesNotExist, LoginOTP.DoesNotExist):
        messages.error(request, "Invalid session. Please login again.")
        return redirect("login")

    if request.method == "POST":
        otp_input = request.POST.get("otp", "").strip()

        if not otp_record.is_valid:
            messages.error(request, "Verification code has expired. Please login again.")
            return redirect("login")

        if otp_record.otp == otp_input:
            # OTP verified - log in the user
            otp_record.is_used = True
            otp_record.save()

            # Clear session data
            del request.session["login_otp_user_id"]
            del request.session["login_otp_id"]

            # Log in
            login(request, user)
            device, browser = _get_user_agent_info(request)
            ip = _get_client_ip(request)
            LoginActivity.objects.create(
                user=user, ip_address=ip, device=device, browser=browser, location="OTP Verified", status="success"
            )

            messages.success(request, f"Welcome back, {user.first_name or user.email}!")
            return redirect("dashboard")
        else:
            messages.error(request, "❌ Invalid verification code. Please try again.")

    return render(
        request,
        "banking/login_otp.html",
        {
            "email": user.email,
            "otp_expires": otp_record.expires_at,
        },
    )


